using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;
using UnityEngine;
using UnityEngine.Events;
using UnityEngine.SceneManagement;
using UnityEngine.UIElements;
using UnityEngine.XR.Interaction.Toolkit.Interactables;
#if ENABLE_INPUT_SYSTEM
using UnityEngine.InputSystem;
#endif

[RequireComponent(typeof(UIDocument))]
[RequireComponent(typeof(XRGrabInteractable))]
[RequireComponent(typeof(Collider))]
[RequireComponent(typeof(Rigidbody))]
public class CourseSelectionUI : MonoBehaviour
{
    [Header("UI Toolkit Assets")]
    [SerializeField] private VisualTreeAsset courseSelectionTree;
    [SerializeField] private StyleSheet courseSelectionStyle;

    [Header("Navigation")]
    [SerializeField] private string vrClassroomSceneName = "VRClassroom";
    [SerializeField] private UnityEvent<CourseData> onCourseSelected;

    [Header("ListView")]
    [SerializeField, Min(120f)] private float listItemHeight = 170f;

    [Header("XR Scrolling")]
    [SerializeField] private float thumbstickScrollSpeed = 1150f;
#if ENABLE_INPUT_SYSTEM
    [SerializeField] private InputActionReference scrollAxisAction;
#endif

    private UIDocument uiDocument;
    private ListView courseList;
    private ScrollView courseListScrollView;
    private TextField searchField;
    private VisualElement thumbnailImage;
    private Label selectedCourseTitle;
    private Label selectedCourseDescription;
    private Label statusLabel;
    private Button openCourseButton;

    private readonly List<CourseData> allCourses = new List<CourseData>();
    private readonly List<CourseData> filteredCourses = new List<CourseData>();
    private CourseData selectedCourse;
    private Texture2D currentThumbnailTexture;

    private const string CourseItemClass = "course-item";
    private const string CourseItemSelectedClass = "course-item-selected";
    private const string StatusErrorClass = "status-error";
    private const string StatusOkClass = "status-ok";

    private async void Start()
    {
        ConfigureGrabInteractable();
        BuildUi();
        await RefreshCourses();
    }

    private void Update()
    {
        if (courseList == null) return;

#if ENABLE_INPUT_SYSTEM
        if (scrollAxisAction == null || scrollAxisAction.action == null) return;
        if (courseListScrollView == null) return;

        Vector2 axis = scrollAxisAction.action.ReadValue<Vector2>();
        if (Mathf.Abs(axis.y) <= 0.08f) return;

        float nextOffset = courseListScrollView.scrollOffset.y - axis.y * thumbstickScrollSpeed * Time.deltaTime;
        nextOffset = Mathf.Max(0f, nextOffset);
        courseListScrollView.scrollOffset = new Vector2(courseListScrollView.scrollOffset.x, nextOffset);
#endif
    }

    private void OnDestroy()
    {
        if (searchField != null)
        {
            searchField.UnregisterValueChangedCallback(OnSearchValueChanged);
        }

        if (openCourseButton != null)
        {
            openCourseButton.clicked -= OpenSelectedCourse;
        }
    }

    public async Task RefreshCourses()
    {
        SetStatus("Đang tải dữ liệu khóa học...", false);

        try
        {
            List<CourseData> courses = await ApiManager.Instance.GetCoursesAsync();
            allCourses.Clear();

            if (courses != null)
            {
                IEnumerable<CourseData> enrolled = courses.Where(IsEnrolledCourse);
                allCourses.AddRange(enrolled);
            }

            ApplySearchFilter(searchField?.value ?? string.Empty);

            if (allCourses.Count == 0)
            {
                SetStatus("Chưa có khóa học đã đăng ký hoặc chưa có tiến độ học.", false);
            }
            else
            {
                SetStatus($"Tải thành công {allCourses.Count} khóa học.", true);
            }
        }
        catch (Exception ex)
        {
            Debug.LogError($"[CourseSelectionUI] Không thể tải danh sách khóa học: {ex.Message}");
            SetStatus("Không thể tải dữ liệu. Kiểm tra mạng, token hoặc endpoint API.", true, true);
            allCourses.Clear();
            ApplySearchFilter(string.Empty);
        }
    }

    private bool IsEnrolledCourse(CourseData course)
    {
        if (course == null) return false;

        bool hasExplicitEnrolledFlag = course.isEnrolled;
        bool hasProgress = course.progress > 0 || course.completedLessons > 0;

        // Nếu backend /api/vr/courses đã chỉ trả về enrolled courses,
        // course có thể chưa có progress (khóa mới đăng ký).
        bool looksLikeValidCourse = !string.IsNullOrWhiteSpace(course.id) && !string.IsNullOrWhiteSpace(course.title);

        return hasExplicitEnrolledFlag || hasProgress || looksLikeValidCourse;
    }

    private void BuildUi()
    {
        uiDocument = GetComponent<UIDocument>();
        if (uiDocument == null)
        {
            Debug.LogError("[CourseSelectionUI] UIDocument component không tồn tại.");
            return;
        }

        if (courseSelectionTree == null)
        {
            Debug.LogError("[CourseSelectionUI] Chưa gán UXML vào courseSelectionTree.");
            return;
        }

        VisualElement root = uiDocument.rootVisualElement;
        root.Clear();

        if (courseSelectionStyle != null)
        {
            root.styleSheets.Add(courseSelectionStyle);
        }

        courseSelectionTree.CloneTree(root);

        searchField = root.Q<TextField>("search-field");
        thumbnailImage = root.Q<VisualElement>("thumbnail-image");
        selectedCourseTitle = root.Q<Label>("selected-course-title");
        selectedCourseDescription = root.Q<Label>("selected-course-description");
        statusLabel = root.Q<Label>("status-label");
        openCourseButton = root.Q<Button>("open-course-button");
        courseList = root.Q<ListView>("course-list");
        courseListScrollView = courseList?.Q<ScrollView>();

        if (searchField != null)
        {
            searchField.value = string.Empty;
            searchField.RegisterValueChangedCallback(OnSearchValueChanged);
            searchField.textEdition.placeholder = "Tìm theo tên hoặc mô tả...";
        }

        if (openCourseButton != null)
        {
            openCourseButton.clicked += OpenSelectedCourse;
            openCourseButton.SetEnabled(false);
        }

        ConfigureListView();
    }

    private void ConfigureListView()
    {
        if (courseList == null) return;

        courseList.fixedItemHeight = listItemHeight;
        courseList.virtualizationMethod = CollectionVirtualizationMethod.FixedHeight;
        courseList.selectionType = SelectionType.Single;
        courseList.itemsSource = filteredCourses;

        // ListView tái sử dụng item visuals để giảm allocations ở runtime VR.
        courseList.makeItem = () =>
        {
            VisualElement row = new VisualElement();
            row.AddToClassList(CourseItemClass);

            Label title = new Label();
            title.name = "item-title";
            title.AddToClassList("course-item-title");

            Label desc = new Label();
            desc.name = "item-desc";
            desc.AddToClassList("course-item-desc");

            row.Add(title);
            row.Add(desc);
            return row;
        };

        courseList.bindItem = (element, index) =>
        {
            if (index < 0 || index >= filteredCourses.Count) return;

            CourseData course = filteredCourses[index];
            Label title = element.Q<Label>("item-title");
            Label desc = element.Q<Label>("item-desc");

            if (title != null) title.text = string.IsNullOrWhiteSpace(course.title) ? "(Không có tiêu đề)" : course.title;
            if (desc != null) desc.text = BuildShortDescription(course.description);

            bool isSelected = selectedCourse != null && selectedCourse.id == course.id;
            element.EnableInClassList(CourseItemSelectedClass, isSelected);
        };

        courseList.selectionChanged += HandleSelectionChanged;
    }

    private void ApplySearchFilter(string query)
    {
        string q = (query ?? string.Empty).Trim();

        IEnumerable<CourseData> result;
        if (string.IsNullOrEmpty(q))
        {
            result = allCourses;
        }
        else
        {
            result = allCourses.Where(c =>
                ContainsIgnoreCase(c.title, q) ||
                ContainsIgnoreCase(c.description, q));
        }

        filteredCourses.Clear();
        filteredCourses.AddRange(result);

        if (courseList != null)
        {
            courseList.Rebuild();
        }

        if (filteredCourses.Count > 0)
        {
            SelectCourse(filteredCourses[0], true);
            if (courseList != null)
            {
                courseList.selectedIndex = 0;
            }
        }
        else
        {
            SelectCourse(null, false);
        }
    }

    private void HandleSelectionChanged(IEnumerable<object> selectedItems)
    {
        object item = selectedItems.FirstOrDefault();
        CourseData selected = item as CourseData;
        SelectCourse(selected, true);
    }

    private void SelectCourse(CourseData course, bool updateListVisual)
    {
        selectedCourse = course;

        if (selectedCourseTitle != null)
        {
            selectedCourseTitle.text = course == null
                ? "Không có khóa học"
                : course.title;
        }

        if (selectedCourseDescription != null)
        {
            selectedCourseDescription.text = course == null
                ? "Không tìm thấy khóa học phù hợp với bộ lọc hiện tại."
                : BuildLongDescription(course.description);
        }

        if (openCourseButton != null)
        {
            openCourseButton.SetEnabled(course != null);
        }

        if (course == null)
        {
            thumbnailImage.style.backgroundImage = StyleKeyword.None;
            return;
        }

        _ = UpdateThumbnailAsync(course.thumbnailUrl);

        if (updateListVisual && courseList != null)
        {
            courseList.RefreshItems();
        }
    }

    private async Task UpdateThumbnailAsync(string thumbnailUrl)
    {
        if (thumbnailImage == null || ApiManager.Instance == null) return;

        if (string.IsNullOrWhiteSpace(thumbnailUrl))
        {
            thumbnailImage.style.backgroundImage = StyleKeyword.None;
            return;
        }

        Texture2D texture = await ApiManager.Instance.DownloadImageAsync(thumbnailUrl);
        if (texture == null || thumbnailImage == null) return;

        currentThumbnailTexture = texture;
        thumbnailImage.style.backgroundImage = new StyleBackground(currentThumbnailTexture);
    }

    private void OpenSelectedCourse()
    {
        if (selectedCourse == null)
        {
            SetStatus("Hãy chọn một khóa học trước khi vào lớp học VR.", true, true);
            return;
        }

        onCourseSelected?.Invoke(selectedCourse);

        if (!string.IsNullOrWhiteSpace(vrClassroomSceneName))
        {
            SceneManager.LoadScene(vrClassroomSceneName);
        }
    }

    private void ConfigureGrabInteractable()
    {
        XRGrabInteractable grab = GetComponent<XRGrabInteractable>();
        Rigidbody body = GetComponent<Rigidbody>();

        body.useGravity = false;
        body.isKinematic = false;
        body.interpolation = RigidbodyInterpolation.Interpolate;
        body.collisionDetectionMode = CollisionDetectionMode.ContinuousSpeculative;

        grab.movementType = XRBaseInteractable.MovementType.VelocityTracking;
        grab.throwOnDetach = false;
        grab.trackPosition = true;
        grab.trackRotation = true;
        grab.smoothPosition = true;
        grab.smoothRotation = true;
    }

    private void OnSearchValueChanged(ChangeEvent<string> evt)
    {
        ApplySearchFilter(evt.newValue);
    }

    private void SetStatus(string message, bool transient, bool isError = false)
    {
        if (statusLabel == null) return;

        statusLabel.text = message;
        statusLabel.EnableInClassList(StatusErrorClass, isError);
        statusLabel.EnableInClassList(StatusOkClass, !isError);

        if (!transient) return;
        CancelInvoke(nameof(ClearStatus));
        Invoke(nameof(ClearStatus), 4f);
    }

    private void ClearStatus()
    {
        if (statusLabel == null) return;
        statusLabel.text = string.Empty;
        statusLabel.RemoveFromClassList(StatusErrorClass);
        statusLabel.RemoveFromClassList(StatusOkClass);
    }

    private static bool ContainsIgnoreCase(string source, string value)
    {
        if (string.IsNullOrEmpty(source) || string.IsNullOrEmpty(value)) return false;
        return source.IndexOf(value, StringComparison.OrdinalIgnoreCase) >= 0;
    }

    private static string BuildShortDescription(string input)
    {
        if (string.IsNullOrWhiteSpace(input)) return "Không có mô tả.";
        string value = input.Trim();
        return value.Length <= 90 ? value : value.Substring(0, 87) + "...";
    }

    private static string BuildLongDescription(string input)
    {
        if (string.IsNullOrWhiteSpace(input)) return "Khóa học chưa có mô tả chi tiết.";
        string value = input.Trim();
        return value.Length <= 220 ? value : value.Substring(0, 217) + "...";
    }
}
